using System.ComponentModel;
using System.Net;
using System.Text;
using System.Text.RegularExpressions;
using Microsoft.Extensions.AI;
using OpenAI;

// ── Tools ────────────────────────────────────────────────────────────
var notepad = new Notepad();

var tools = new AIFunction[]
{
    AIFunctionFactory.Create(WebSearchTool.SearchAsync),
    AIFunctionFactory.Create(notepad.SaveNote),
    AIFunctionFactory.Create(notepad.GetNotes),
};

// ── Chat client with automatic tool invocation ───────────────────────
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable.");

IChatClient client = new ChatClientBuilder(
        new OpenAIClient(apiKey).GetChatClient("gpt-4o").AsIChatClient())
    .UseFunctionInvocation()
    .Build();

// ── System prompt ────────────────────────────────────────────────────
const string systemPrompt = """
    You are a research agent. Your job is to thoroughly research a topic
    the user provides. Follow these steps:

    1. Use the SearchWeb tool to find information. Make multiple searches
       with varied queries to get broad coverage.
    2. Use the SaveNote tool to record each key finding as you go.
    3. After gathering enough information, use GetNotes to review everything
       and then provide a comprehensive, well-organized summary to the user.

    Be thorough but concise. Cite sources when possible.
    """;

// ── Get topic ────────────────────────────────────────────────────────
Console.Write("Enter a research topic: ");
var topic = Console.ReadLine()?.Trim();
if (string.IsNullOrEmpty(topic))
{
    Console.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine($"\n🔍 Researching: {topic}\n");

// ── Run the agent ────────────────────────────────────────────────────
var messages = new List<ChatMessage>
{
    new(ChatRole.System, systemPrompt),
    new(ChatRole.User,
        $"Please research the following topic and provide a comprehensive summary: {topic}"),
};

var options = new ChatOptions { Tools = [.. tools] };
var response = await client.GetResponseAsync(messages, options);

Console.WriteLine("\n════════════════════════════════════════");
Console.WriteLine("📋 RESEARCH SUMMARY");
Console.WriteLine("════════════════════════════════════════\n");
Console.WriteLine(response.Text);

if (notepad.Notes.Count > 0)
{
    Console.WriteLine("\n────────────────────────────────────────");
    Console.WriteLine($"📝 {notepad.Notes.Count} note(s) saved during research.");
}

// ═════════════════════════════════════════════════════════════════════
// Tool implementations
// ═════════════════════════════════════════════════════════════════════

/// <summary>Searches the web via DuckDuckGo (no API key required).</summary>
public static partial class WebSearchTool
{
    private static readonly HttpClient Http = new();

    static WebSearchTool()
    {
        Http.DefaultRequestHeaders.UserAgent.ParseAdd(
            "Mozilla/5.0 (compatible; ResearchAgent/1.0)");
        Http.Timeout = TimeSpan.FromSeconds(15);
    }

    [Description("Search the web for a query and return the top result snippets.")]
    public static async Task<string> SearchAsync(
        [Description("The search query")] string query)
    {
        Console.WriteLine($"  🌐 Searching: \"{query}\"");

        try
        {
            var encoded = Uri.EscapeDataString(query);
            var url = $"https://html.duckduckgo.com/html/?q={encoded}";
            var html = await Http.GetStringAsync(url);

            var results = new StringBuilder();
            int count = 0;

            var links = ResultTitleRegex().Matches(html);
            var snippets = ResultSnippetRegex().Matches(html);

            for (int i = 0; i < Math.Min(links.Count, 5); i++)
            {
                count++;
                var title = StripHtml(links[i].Groups[1].Value);
                var snippet = i < snippets.Count
                    ? StripHtml(snippets[i].Groups[1].Value)
                    : "(no snippet)";

                results.AppendLine($"{count}. {title}");
                results.AppendLine($"   {snippet}");
                results.AppendLine();
            }

            return count > 0
                ? results.ToString()
                : "No results found for this query.";
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}";
        }
    }

    private static string StripHtml(string html)
    {
        var text = HtmlTagRegex().Replace(html, "");
        return WebUtility.HtmlDecode(text).Trim();
    }

    [GeneratedRegex(@"<a[^>]+class=""result__a""[^>]*>(.*?)</a>", RegexOptions.Singleline)]
    private static partial Regex ResultTitleRegex();

    [GeneratedRegex(@"<a[^>]+class=""result__snippet""[^>]*>(.*?)</a>", RegexOptions.Singleline)]
    private static partial Regex ResultSnippetRegex();

    [GeneratedRegex(@"<[^>]+>")]
    private static partial Regex HtmlTagRegex();
}

/// <summary>In-memory notepad for the agent to store research findings.</summary>
public class Notepad
{
    public List<(string Title, string Content)> Notes { get; } = [];

    [Description("Save a research note with a title and content for later reference.")]
    public string SaveNote(
        [Description("Short descriptive title")] string title,
        [Description("The note content with key facts")] string content)
    {
        Notes.Add((title, content));
        Console.WriteLine($"  📝 Note saved: \"{title}\"");
        return $"Note #{Notes.Count} saved: {title}";
    }

    [Description("Retrieve all saved research notes to review findings.")]
    public string GetNotes()
    {
        if (Notes.Count == 0)
            return "No notes have been saved yet.";

        var sb = new StringBuilder();
        for (int i = 0; i < Notes.Count; i++)
        {
            sb.AppendLine($"--- Note #{i + 1}: {Notes[i].Title} ---");
            sb.AppendLine(Notes[i].Content);
            sb.AppendLine();
        }
        return sb.ToString();
    }
}

